import re

FILE_BLOCK_PATTERN = r"\n?\[FILE\]\n.*?\n\[/FILE\]"


def _require_string(value, label):
    if not isinstance(value, str):
        raise TypeError(f"public_search inputs: {label} must be string")
    return value


def _clean_user_query(content):
    text = re.sub(FILE_BLOCK_PATTERN, "", content, flags=re.DOTALL)
    text = re.sub(r"\n{3,}", "\n\n", text).strip()
    if text == "":
        return "проанализировать приложенные файлы"
    return text


async def run(args, state):
    content = _require_string(state["content"], "state.content")
    files = state["files"]
    if not isinstance(files, list):
        raise TypeError("public_search inputs: state.files must be array")

    file_names = []
    for index, item in enumerate(files):
        if not isinstance(item, dict):
            raise TypeError(f"public_search inputs: state.files[{index}] must be object")
        original_name = item["original_name"]
        if not isinstance(original_name, str) or original_name.strip() == "":
            raise TypeError(f"public_search inputs: state.files[{index}].original_name must be non-empty string")
        file_names.append(original_name.strip())

    user_query = _clean_user_query(content)
    return {
        "search_user_query": user_query,
        "search_effective_query": user_query,
        "search_has_files": len(file_names) > 0,
        "search_file_names": file_names,
        "search_file_context": "",
    }

