MAX_FILE_CONTEXT_CHARS = 2500


def _require_non_empty_string(value, label):
    if not isinstance(value, str):
        raise TypeError(f"public_search query: {label} must be string")
    text = value.strip()
    if text == "":
        raise ValueError(f"public_search query: {label} must be non-empty")
    return text


def _require_string(value, label):
    if not isinstance(value, str):
        raise TypeError(f"public_search query: {label} must be string")
    return value


async def run(args, state):
    user_query = _require_non_empty_string(state["search_user_query"], "state.search_user_query")
    file_context = _require_string(state["search_file_context"], "state.search_file_context").strip()
    if file_context == "":
        return {"search_effective_query": user_query}

    clipped_context = file_context[:MAX_FILE_CONTEXT_CHARS].strip()
    effective_query = (
        f"{user_query}\n\n"
        "Краткий контекст приложенных файлов для поиска:\n"
        f"{clipped_context}"
    )
    return {"search_effective_query": effective_query}

