VALID_SEARCH_MODES = {"quick", "deep", "research"}


def _mode(state):
    variables = state["variables"]
    if not isinstance(variables, dict):
        raise TypeError("public_search insights event: state.variables must be object")
    mode = variables["search_mode"]
    if mode not in VALID_SEARCH_MODES:
        raise ValueError("public_search insights event: variables.search_mode is invalid")
    return mode


async def run(args, state):
    payload = {
        "kind": "public_search_serp_update",
        "version": 1,
        "flow_id": "public_search",
        "phase": "insights",
        "mode": _mode(state),
        "query": state["search_user_query"],
        "result_insights": state["search_result_insights"],
    }
    await capability(
        "state.push_ui_event",
        event_type="search/serp/insights_ready",
        payload=payload,
        source="public_search",
    )
    return {}

