import json

VALID_SEARCH_MODES = {"quick", "deep", "research"}


def _require_dict(state, key):
    if key not in state:
        raise ValueError(f"public_search artifact: state.{key} is required")
    value = state[key]
    if not isinstance(value, dict):
        raise TypeError(f"public_search artifact: state.{key} must be object")
    return value


def _require_list(state, key):
    if key not in state:
        raise ValueError(f"public_search artifact: state.{key} is required")
    value = state[key]
    if not isinstance(value, list):
        raise TypeError(f"public_search artifact: state.{key} must be array")
    return value


def _require_bool(state, key):
    if key not in state:
        raise ValueError(f"public_search artifact: state.{key} is required")
    value = state[key]
    if not isinstance(value, bool):
        raise TypeError(f"public_search artifact: state.{key} must be boolean")
    return value


def _require_string(state, key):
    if key not in state:
        raise ValueError(f"public_search artifact: state.{key} is required")
    value = state[key]
    if not isinstance(value, str):
        raise TypeError(f"public_search artifact: state.{key} must be string")
    return value.strip()


def _require_str(state, key):
    text = _require_string(state, key)
    if text == "":
        raise ValueError(f"public_search artifact: state.{key} must be non-empty")
    return text


async def run(args, state):
    variables = _require_dict(state, "variables")
    if "search_mode" not in variables:
        raise ValueError("public_search artifact: variables.search_mode is required")
    mode = variables["search_mode"]
    if mode not in VALID_SEARCH_MODES:
        raise ValueError("public_search artifact: variables.search_mode is invalid")
    has_files = _require_bool(state, "search_has_files")

    artifact = {
        "kind": "public_search_serp",
        "version": 1,
        "flow_id": "public_search",
        "mode": mode,
        "query": _require_str(state, "search_user_query"),
        "effective_query": _require_str(state, "search_effective_query"),
        "file_context": _require_string(state, "search_file_context") if has_files else "",
        "answer": _require_str(state, "response"),
        "results": _require_list(state, "search_results"),
        "providers": _require_dict(state, "search_providers_status"),
        "suggestions": _require_list(state, "search_suggestions"),
        "followups": _require_list(state, "search_followups"),
        "result_insights": _require_list(state, "search_result_insights"),
    }
    await capability(
        "state.push_ui_event",
        event_type="search/serp/completed",
        payload=artifact,
        source="public_search",
    )
    response = json.dumps(artifact, ensure_ascii=False, separators=(",", ":"))
    return {"response": response}
